const EARTH_DAY_B64 = "";

class Earth {
  constructor(scene) {
    this.scene = scene;
    this.group = new THREE.Group();
    this.scene.add(this.group);
    this.earthMesh = null;
    this.cloudMesh = null;
    this.atmosphereMesh = null;
    this.glowMesh = null;
    this.radius = 5;
    this.onReady = null;
    this.sunDirection = new THREE.Vector3(5, 1, 3).normalize();
    this.init();
  }

  init() {
    this.createAtmosphere();
    this.createOuterGlow();
    this.loadTextures();
  }

  loadTextures() {
    const loader = new THREE.TextureLoader();
    loader.crossOrigin = 'anonymous';

    const textures = {};
    let loaded = 0;
    const total = 3;

    const done = (name, t) => {
      textures[name] = t;
      loaded++;
      if (window.updateLoader) window.updateLoader(Math.round((loaded / total) * 90));
      if (loaded === total) this.buildEarth(textures);
    };

    // Day texture — use embedded base64 (guaranteed, no CORS)
    const img = new Image();
    img.onload = () => {
      const tex = new THREE.Texture(img);
      tex.needsUpdate = true;
      done('day', tex);
    };
    img.onerror = () => done('day', null);
    img.src = 'data:image/png;base64,' + EARTH_DAY_B64;

    // Night + specular from CDN (optional, graceful fallback)
    const tryLoad = (urls, name, index = 0) => {
      if (index >= urls.length) { done(name, null); return; }
      loader.load(urls[index], t => done(name, t), undefined, () => tryLoad(urls, name, index + 1));
    };

    tryLoad([
      'https://cdn.jsdelivr.net/npm/three@0.128.0/examples/textures/planets/earth_lights_2048.png',
    ], 'night');

    tryLoad([
      'https://cdn.jsdelivr.net/npm/three@0.128.0/examples/textures/planets/earth_specular_2048.jpg',
    ], 'specular');
  }

  buildEarth(textures) {
    const geometry = new THREE.SphereGeometry(this.radius, 96, 96);

    let material;

    if (textures.day) {
      material = new THREE.ShaderMaterial({
        uniforms: {
          dayTexture:      { value: textures.day },
          nightTexture:    { value: textures.night },
          specularTexture: { value: textures.specular },
          sunDirection:    { value: this.sunDirection.clone() },
          hasNight:        { value: textures.night  ? 1.0 : 0.0 },
          hasSpecular:     { value: textures.specular ? 1.0 : 0.0 },
        },
        vertexShader: `
          varying vec2 vUv;
          varying vec3 vNormal;
          varying vec3 vWorldPos;
          void main() {
            vUv = uv;
            vNormal = normalize(normalMatrix * normal);
            vWorldPos = (modelMatrix * vec4(position, 1.0)).xyz;
            gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
          }
        `,
        fragmentShader: `
          uniform sampler2D dayTexture;
          uniform sampler2D nightTexture;
          uniform sampler2D specularTexture;
          uniform vec3 sunDirection;
          uniform float hasNight;
          uniform float hasSpecular;
          varying vec2 vUv;
          varying vec3 vNormal;
          varying vec3 vWorldPos;

          void main() {
            vec3 normal = normalize(vNormal);
            vec3 sun = normalize(sunDirection);
            float sunDot = dot(normal, sun);
            float dayNight = smoothstep(-0.2, 0.3, sunDot);

            vec3 dayColor = texture2D(dayTexture, vUv).rgb;
            vec3 nightColor = hasNight > 0.5
              ? texture2D(nightTexture, vUv).rgb * 2.2
              : vec3(0.0);

            float diffuse = max(0.0, sunDot);
            vec3 dayLit = dayColor * (0.08 + diffuse * 1.1);

            float specMask = hasSpecular > 0.5
              ? texture2D(specularTexture, vUv).r
              : 0.25;
            vec3 viewDir = normalize(cameraPosition - vWorldPos);
            vec3 halfVec = normalize(sun + viewDir);
            float spec = pow(max(dot(normal, halfVec), 0.0), 64.0) * specMask * 0.6 * dayNight;
            dayLit += vec3(spec * 0.7, spec * 0.85, spec);

            vec3 color = mix(nightColor, dayLit, dayNight);
            color = pow(max(color, vec3(0.0)), vec3(0.9));
            gl_FragColor = vec4(color, 1.0);
          }
        `
      });
    } else {
      material = this.buildProceduralMaterial();
    }

    this.earthMesh = new THREE.Mesh(geometry, material);
    this.group.add(this.earthMesh);
    this.createClouds();

    if (window.updateLoader) window.updateLoader(100);
    setTimeout(() => { if (this.onReady) this.onReady(); }, 200);
  }

  buildProceduralMaterial() {
    return new THREE.ShaderMaterial({
      uniforms: {
        sunDirection: { value: this.sunDirection.clone() },
        time: { value: 0.0 }
      },
      vertexShader: `
        varying vec2 vUv;
        varying vec3 vNormal;
        varying vec3 vWorldPos;
        void main() {
          vUv = uv;
          vNormal = normalize(normalMatrix * normal);
          vWorldPos = (modelMatrix * vec4(position, 1.0)).xyz;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        uniform vec3 sunDirection;
        uniform float time;
        varying vec2 vUv;
        varying vec3 vNormal;
        varying vec3 vWorldPos;

        float hash(vec2 p) { return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453); }
        float noise(vec2 p) {
          vec2 i=floor(p),f=fract(p);
          f=f*f*(3.0-2.0*f);
          return mix(mix(hash(i),hash(i+vec2(1,0)),f.x),mix(hash(i+vec2(0,1)),hash(i+vec2(1,1)),f.x),f.y);
        }
        float fbm(vec2 p) {
          float v=0.0,a=0.5;
          for(int i=0;i<6;i++){v+=a*noise(p);p*=2.1;a*=0.5;}
          return v;
        }

        void main() {
          float u = vUv.x;
          float v = vUv.y;
          float lat = abs(v - 0.5) * 2.0;

          float height = fbm(vec2(u*2.8, v*2.8)) + fbm(vec2(u*6.0+1.3, v*6.0+2.1))*0.35 - 0.42;
          float moisture = fbm(vec2(u*3.1+5.0, v*3.1+3.0));
          bool isOcean = height < 0.0;

          vec3 deepOcean    = vec3(0.02, 0.10, 0.30);
          vec3 shallowOcean = vec3(0.04, 0.20, 0.50);
          vec3 coast        = vec3(0.10, 0.30, 0.55);
          vec3 forest       = vec3(0.08, 0.28, 0.08);
          vec3 grassland    = vec3(0.18, 0.40, 0.10);
          vec3 savanna      = vec3(0.40, 0.38, 0.12);
          vec3 desert       = vec3(0.55, 0.42, 0.18);
          vec3 snow         = vec3(0.90, 0.93, 0.95);
          vec3 mountain     = vec3(0.30, 0.26, 0.22);
          vec3 iceSheet     = vec3(0.85, 0.90, 0.95);

          vec3 baseColor;
          if (isOcean) {
            float depth = clamp(-height * 3.5, 0.0, 1.0);
            baseColor = mix(coast, mix(shallowOcean, deepOcean, depth), depth * 0.8);
          } else {
            if (lat > 0.78) {
              baseColor = mix(mountain, iceSheet, smoothstep(0.78, 0.92, lat));
            } else if (height > 0.80) {
              baseColor = snow;
            } else if (height > 0.60) {
              baseColor = mix(mountain, snow, (height - 0.60) * 2.5);
            } else if (moisture > 0.55) {
              baseColor = mix(grassland, forest, (moisture - 0.55) * 4.0);
            } else if (moisture > 0.35) {
              baseColor = mix(savanna, grassland, (moisture - 0.35) * 5.0);
            } else {
              baseColor = mix(desert, savanna, moisture * 3.0);
            }
          }

          vec3 normal = normalize(vNormal);
          vec3 sun = normalize(sunDirection);
          float sunDot = dot(normal, sun);
          float dayNight = smoothstep(-0.18, 0.28, sunDot);
          float diffuse = max(0.0, sunDot);

          vec3 dayLit = baseColor * (0.08 + diffuse * 1.2);

          if (isOcean) {
            vec3 viewDir = normalize(cameraPosition - vWorldPos);
            vec3 halfVec = normalize(sun + viewDir);
            float spec = pow(max(dot(normal, halfVec), 0.0), 90.0) * 0.55 * dayNight;
            dayLit += vec3(spec * 0.7, spec * 0.85, spec * 1.0);
          }

          vec3 nightColor = isOcean ? vec3(0.0) : vec3(1.0, 0.85, 0.4) * 0.10;
          vec3 color = mix(nightColor, dayLit, dayNight);
          gl_FragColor = vec4(pow(max(color, vec3(0.0)), vec3(0.90)), 1.0);
        }
      `
    });
  }

  createClouds() {
    const geometry = new THREE.SphereGeometry(this.radius + 0.06, 48, 48);
    const material = new THREE.ShaderMaterial({
      uniforms: { time: { value: 0.0 } },
      vertexShader: `
        varying vec2 vUv;
        varying vec3 vNormal;
        void main() {
          vUv = uv;
          vNormal = normalize(normalMatrix * normal);
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
        }
      `,
      fragmentShader: `
        uniform float time;
        varying vec2 vUv;
        varying vec3 vNormal;
        float hash(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453);}
        float noise(vec2 p){
          vec2 i=floor(p),f=fract(p);f=f*f*(3.0-2.0*f);
          return mix(mix(hash(i),hash(i+vec2(1,0)),f.x),mix(hash(i+vec2(0,1)),hash(i+vec2(1,1)),f.x),f.y);
        }
        float fbm(vec2 p){float v=0.0,a=0.5;for(int i=0;i<6;i++){v+=a*noise(p);p*=2.0;a*=0.5;}return v;}
        void main() {
          vec2 uv=vUv+vec2(time*0.004,0.0);
          float cloud=fbm(uv*3.5)*fbm(uv*1.8+vec2(3.2,7.1));
          cloud=smoothstep(0.22,0.55,cloud);
          vec3 viewDir=normalize(cameraPosition-vec3(0.0));
          float edge=dot(normalize(vNormal),viewDir);
          gl_FragColor=vec4(1.0,1.0,1.0,cloud*0.28*smoothstep(0.0,0.3,edge));
        }
      `,
      transparent: true,
      depthWrite: false,
      blending: THREE.NormalBlending
    });
    this.cloudMesh = new THREE.Mesh(geometry, material);
    this.group.add(this.cloudMesh);
  }

  createAtmosphere() {
    const geometry = new THREE.SphereGeometry(this.radius + 0.18, 64, 64);
    const material = new THREE.ShaderMaterial({
      uniforms: { sunDirection: { value: this.sunDirection.clone() } },
      vertexShader: `
        varying vec3 vNormal;
        varying vec3 vWorldPos;
        void main() {
          vNormal = normalize(normalMatrix * normal);
          vWorldPos = (modelMatrix * vec4(position,1.0)).xyz;
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
        }
      `,
      fragmentShader: `
        uniform vec3 sunDirection;
        varying vec3 vNormal;
        varying vec3 vWorldPos;
        void main() {
          vec3 viewDir=normalize(cameraPosition-vWorldPos);
          float rim=pow(1.0-max(dot(viewDir,vNormal),0.0),2.8);
          float sunFacing=dot(vNormal,normalize(sunDirection))*0.5+0.5;
          vec3 atmoColor=mix(vec3(0.02,0.06,0.2),vec3(0.2,0.55,1.0),sunFacing);
          gl_FragColor=vec4(atmoColor,rim*0.7);
        }
      `,
      transparent: true, depthWrite: false,
      side: THREE.FrontSide, blending: THREE.AdditiveBlending
    });
    this.atmosphereMesh = new THREE.Mesh(geometry, material);
    this.group.add(this.atmosphereMesh);
  }

  createOuterGlow() {
    const geometry = new THREE.SphereGeometry(this.radius + 0.8, 32, 32);
    const material = new THREE.ShaderMaterial({
      vertexShader: `
        varying vec3 vNormal;
        void main() {
          vNormal = normalize(normalMatrix * normal);
          gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
        }
      `,
      fragmentShader: `
        varying vec3 vNormal;
        void main() {
          float rim=pow(1.0-max(dot(normalize(cameraPosition),vNormal),0.0),4.5)*0.35;
          gl_FragColor=vec4(0.08,0.35,1.0,rim);
        }
      `,
      transparent: true, depthWrite: false,
      side: THREE.BackSide, blending: THREE.AdditiveBlending
    });
    this.glowMesh = new THREE.Mesh(geometry, material);
    this.group.add(this.glowMesh);
  }

  latLngToVec3(lat, lng, altRadius) {
    const phi   = (90 - lat)  * (Math.PI / 180);
    const theta = (lng + 180) * (Math.PI / 180);
    const r = altRadius !== undefined ? altRadius : this.radius;
    const pos = new THREE.Vector3(
      -r * Math.sin(phi) * Math.cos(theta),
       r * Math.cos(phi),
       r * Math.sin(phi) * Math.sin(theta)
    );
    pos.applyEuler(this.group.rotation);
    return pos;
  }

  update(time) {
    if (this.cloudMesh) {
      this.cloudMesh.material.uniforms.time.value = time * 0.001;
    }
    if (this.earthMesh && this.earthMesh.material.uniforms.sunDirection) {
      const sunDir = new THREE.Vector3(
        Math.cos(time * 0.00004),
        0.12,
        Math.sin(time * 0.00004)
      ).normalize();
      this.sunDirection.copy(sunDir);
      this.earthMesh.material.uniforms.sunDirection.value = sunDir;
      if (this.atmosphereMesh) {
        this.atmosphereMesh.material.uniforms.sunDirection.value = sunDir;
      }
    }
    if (this.earthMesh && this.earthMesh.material.uniforms.time) {
      this.earthMesh.material.uniforms.time.value = time * 0.001;
    }
  }
}
